package com.digitalizha.apkcloner;

import android.util.Base64;

import java.io.ByteArrayInputStream;
import java.security.KeyFactory;
import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.security.spec.PKCS8EncodedKeySpec;

final class DebugKeyProvider {
    private DebugKeyProvider() {}

    // Debug key bawaan untuk menandatangani APK hasil clone.
    // Jangan dipakai untuk produksi / app penting. Semua hasil clone akan pakai signature baru ini.
    private static final String PRIVATE_KEY_PKCS8_BASE64 = "";

    private static final String CERT_X509_BASE64 = "";

    static PrivateKey privateKey() throws Exception {
        byte[] keyBytes = Base64.decode(PRIVATE_KEY_PKCS8_BASE64, Base64.DEFAULT);
        return KeyFactory.getInstance("RSA").generatePrivate(new PKCS8EncodedKeySpec(keyBytes));
    }

    static X509Certificate certificate() throws Exception {
        byte[] certBytes = Base64.decode(CERT_X509_BASE64, Base64.DEFAULT);
        CertificateFactory factory = CertificateFactory.getInstance("X.509");
        return (X509Certificate) factory.generateCertificate(new ByteArrayInputStream(certBytes));
    }
}
